import postgres from 'postgres';
const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });
const D = '9d09fa89-3a46-465e-a98b-837287c9e22a';

console.log('=== SETTINGS ===');
const s = await sql`select key, value from settings where key in ('default_extraction_route','default_vision_route','model_pool_extraction','enforce_model_capabilities','default_interview_route','default_translation_route') order by key`;
for (const r of s) console.log(r.key, '=', JSON.stringify(r.value));

console.log('\n=== model_runs TODAY grouped by task/route ===');
const g = await sql`select task_type, provider, model, count(*)::int n, min(created_at) first, max(created_at) last
  from model_runs where created_at > now() - interval '24 hours'
  group by task_type, provider, model order by last desc`;
for (const r of g) console.log(JSON.stringify({task:r.task_type, route:r.provider+'/'+r.model, n:r.n, first:r.first, last:r.last}));

console.log('\n=== doc status ===');
const [d] = await sql`select status, processing_error, processed_at, updated_at from documents where id=${D}`;
console.log(JSON.stringify(d));

console.log('\n=== model_capabilities (extraction/vision candidates) ===');
const mc = await sql`select route_id, supports_structured_outputs, supports_vision, input_cost_per_million, output_cost_per_million
  from model_capabilities where route_id in ('openai/gpt-4o-mini','openai/gpt-4.1-mini','google/gemini-2.5-flash','google/gemini-3.1-flash-lite','qwen/qwen3-vl-235b-a22b-thinking') order by route_id`;
for (const r of mc) console.log(JSON.stringify(r));

console.log('\n=== recent ingestion model_runs (12) ===');
const runs = await sql`select task_type,provider,model,success,input_tokens,output_tokens,latency_ms,created_at
  from model_runs where created_at > now() - interval '24 hours' and (task_type ilike '%ingestion%' or task_type ilike '%vision%' or task_type ilike '%transcri%' or task_type ilike '%extract%') order by created_at desc limit 12`;
for (const r of runs) console.log(JSON.stringify({task:r.task_type, route:r.provider+'/'+r.model, ok:r.success, in:r.input_tokens, out:r.output_tokens, lat_s:(r.latency_ms/1000).toFixed(1), at:r.created_at}));

await sql.end();

import postgres from 'postgres';
const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });
const tbls = ['model_capabilities','model_runs','model_run_attempts','extraction_batches','job_runs','claims','claim_evidence','document_chunks'];
for (const t of tbls) {
  const c = await sql`select column_name, data_type from information_schema.columns where table_name=${t} order by ordinal_position`;
  console.log(`\n=== ${t} ===`);
  console.log(c.map(r=>r.column_name).join(', '));
}
await sql.end();

import postgres from 'postgres';
const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });
const D = '9d09fa89-3a46-465e-a98b-837287c9e22a';

console.log('=== model_capabilities ===');
const mc = await sql`select id, provider, structured_outputs, vision, prompt_per_1m_usd, completion_per_1m_usd
  from model_capabilities where id in ('openai/gpt-4o-mini','openai/gpt-4.1-mini','google/gemini-2.5-flash','google/gemini-3.1-flash-lite','qwen/qwen3-vl-235b-a22b-thinking') order by id`;
for (const r of mc) console.log(JSON.stringify(r));

console.log('\n=== latest 6 model_runs (any task, ingestion-ish) ===');
const runs = await sql`select id, task_type, provider, model, success, error, input_tokens, output_tokens, cost_usd, latency_ms, created_at
  from model_runs where created_at > now()-interval '20 hours' order by created_at desc limit 10`;
for (const r of runs) console.log(JSON.stringify({id:r.id, task:r.task_type, route:r.provider+'/'+r.model, ok:r.success, err:r.error, in:r.input_tokens, out:r.output_tokens, lat_s:(r.latency_ms/1e3).toFixed(1), at:r.created_at}));

console.log('\n=== latest model_run_attempts (12) ===');
const att = await sql`select task_type, slot, attempt_index, route_id, provider, model_id, is_primary, status, error, created_at
  from model_run_attempts where created_at > now()-interval '20 hours' order by created_at desc limit 12`;
for (const a of att) console.log(JSON.stringify({task:a.task_type, slot:a.slot, idx:a.attempt_index, route:a.route_id, model:a.model_id, primary:a.is_primary, status:a.status, err:a.error, at:a.created_at}));

console.log('\n=== latest extraction_batches (3) ===');
const eb = await sql`select status, batch_type, jsonb_array_length(coalesce(raw_model_output->'claims','[]'::jsonb)) returned,
   validation_attempt_count, consecutive_quote_failure_count, route_ids_attempted, error, validation_summary, created_at
  from extraction_batches order by created_at desc limit 3`;
for (const b of eb) console.log(JSON.stringify({status:b.status, type:b.batch_type, returned:b.returned, val_att:b.validation_attempt_count, quote_fail:b.consecutive_quote_failure_count, routes:b.route_ids_attempted, err:b.error, summary:b.validation_summary, at:b.created_at}));

console.log('\n=== latest 3 job_runs for doc ===');
const jr = await sql`select job_type, status, started_at, finished_at, output_json, error from job_runs
  where input_json->>'documentId'=${D} order by started_at desc limit 3`;
for (const j of jr) console.log(JSON.stringify({type:j.job_type, status:j.status, started:j.started_at, output:j.output_json, err:j.error}));

await sql.end();

