import postgres from 'postgres';
const sql = postgres(process.env.PROD_URL, { max:1, prepare:false, connect_timeout:25 });

console.log('=== ALL document-ingestion extraction attempts last 20h (route -> status counts) ===');
const a = await sql`select route_id, model_id, status, count(*)::int n, max(error) sample_err
  from model_run_attempts where task_type='document-ingestion' and slot='extraction' and created_at > now()-interval '20 hours'
  group by route_id, model_id, status order by route_id, status`;
for (const r of a) console.log(JSON.stringify({route:r.route_id, model:r.model_id, status:r.status, n:r.n, err:(r.sample_err||'').slice(0,90)}));

console.log('\n=== Did gemini-2.5-flash EVER succeed on extraction? (any time) ===');
const g = await sql`select status, count(*)::int n, max(created_at) last from model_run_attempts
  where task_type='document-ingestion' and slot='extraction' and model_id ilike '%gemini-2.5-flash%' group by status`;
for (const r of g) console.log(JSON.stringify(r));

console.log('\n=== Did gpt-4o-mini / gpt-4.1-mini EVER succeed on extraction? ===');
const o = await sql`select model_id, status, count(*)::int n, max(created_at) last from model_run_attempts
  where task_type='document-ingestion' and slot='extraction' and (model_id ilike '%gpt-4o-mini%' or model_id ilike '%gpt-4.1-mini%') group by model_id, status order by model_id, status`;
for (const r of o) console.log(JSON.stringify(r));

console.log('\n=== gemini-2.5-flash extraction success history full ===');
const gh = await sql`select route_id, status, error, latency_ms, created_at from model_run_attempts
  where task_type='document-ingestion' and slot='extraction' and model_id ilike '%gemini-2.5-flash%' order by created_at desc limit 8`;
for (const r of gh) console.log(JSON.stringify({route:r.route_id, status:r.status, err:(r.error||'').slice(0,60), lat:r.latency_ms, at:r.created_at}));

await sql.end();

