import postgres from 'postgres';
const sql=postgres(process.env.PROD_URL,{max:1,prepare:false,connect_timeout:25});
const sleep=ms=>new Promise(r=>setTimeout(r,ms));
const D=process.env.DOC;
let s, n=0;
while(n++<32){ const r=await sql`select status from documents where id=${D}`; s=r[0]?.status;
  if(s==='complete'||s==='failed') break; await sleep(20000); }
console.log('FINAL status:', s, 'after', n, 'checks');
await sql.end();

