PROD_URL="postgresql://postgres.eqccjfbyrywsqkxxpjvg:ECUCkNBgLLbdamXtAu5uL2QcMhjswfSiJsAxdW9hgaEI26KL9!@aws-1-us-east-1.pooler.supabase.com:5432/postgres" node -e '
import("postgres").then(async ({default:postgres})=>{
const sql=postgres(process.env.PROD_URL,{max:1,prepare:false,connect_timeout:25});
const D="9d09fa89-3a46-465e-a98b-837287c9e22a";
const t=await sql`select count(*)::int chunks, sum(length(raw_text))::int chars, string_agg(raw_text,e'"'"'\n'"'"') t from document_chunks where document_id=${D}`;
const txt=t[0].t||"";
console.log("V1 qwen3-vl transcription:",JSON.stringify({chunks:t[0].chunks,chars:t[0].chars,edges:(txt.match(/-->/g)||[]).length}));
const [vr]=await sql`select input_tokens,output_tokens,latency_ms,cost_usd from model_runs where task_type=${"document-ingestion-vision"} order by created_at desc limit 1`;
console.log("V1 vision run:",JSON.stringify({in:vr.input_tokens,out:vr.output_tokens,lat_s:(vr.latency_ms/1e3).toFixed(1),cost:vr.cost_usd}));
console.log("\n=== FINAL settings ===");
const s=await sql`select key,value from settings where key in ('"'"'default_extraction_route'"'"','"'"'default_vision_route'"'"','"'"'model_pool_extraction'"'"','"'"'enforce_model_capabilities'"'"') order by key`;
for(const r of s) console.log(r.key,"=",JSON.stringify(r.value),"(raw:",JSON.stringify(JSON.stringify(r.value)).slice(0,60),")");
const [d]=await sql`select status from documents where id=${D}`;
console.log("doc status:",d.status);
const cl=await sql`select c.claim_type,c.summary,ce.exact_quote from claims c join claim_evidence ce on ce.claim_id=c.id join document_chunks dc on dc.id=ce.source_document_chunk_id where dc.document_id=${D} order by c.created_at`;
console.log("\n=== FINAL CLAIMS ("+cl.length+") ===");
cl.forEach((c,i)=>console.log(`[${i+1}] (${c.claim_type}) ${c.summary}`));
console.log("\n=== FIRST CHUNK (transcription sample) ===");
const [c0]=await sql`select raw_text from document_chunks where document_id=${D} order by chunk_index limit 1`;
console.log(c0.raw_text.slice(0,1400));
await sql.end();
})' 2>&1 | head -n 60

